#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <stdint.h>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

#define OMP_CHECK(x) do { \
  int err_ = (x); \
  if (err_ != 0) { \
    printf("OpenMP runtime error %s:%d: %d\n", __FILE__, __LINE__, err_); \
    exit(1); \
  } \
} while (0)

template<typename T>
void conv1d_kernel(const T *in,
                   T *out,
                   const T *mask,
                   const int input_width,
                   const int mask_width,
                   const int bs)
{
  const int grids = input_width / bs;
#pragma omp target teams distribute parallel for is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template<typename T>
void conv1d_tiled_kernel(const T *in,
                         T *out,
                         const T *mask,
                         const int input_width,
                         const int mask_width,
                         const int bs)
{
  const int grids = input_width / bs;
#pragma omp target teams distribute parallel for is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  for (int i = 0; i < input_width; i++) {
    const int n = mask_width / 2;
    const int block = i / bs;
    const int local = i - block * bs;

    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      const int tile_idx = local + j;
      int global_idx;

      if (tile_idx < n) {
        global_idx = (block - 1) * bs + (bs - n + tile_idx);
      } else if (tile_idx < n + bs) {
        global_idx = block * bs + (tile_idx - n);
      } else {
        global_idx = (block + 1) * bs + (tile_idx - (n + bs));
      }

      T v = 0;
      if (global_idx >= 0 && global_idx < input_width) {
        v = in[global_idx];
      }
      s += v * mask[j];
    }
    out[i] = s;
  }
}

template<typename T>
void conv1d_tiled_caching_kernel(const T *in,
                                 T *out,
                                 const T *mask,
                                 const int input_width,
                                 const int mask_width,
                                 const int bs)
{
  const int grids = input_width / bs;
#pragma omp target teams distribute parallel for is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  for (int i = 0; i < input_width; i++) {
    const int block = i / bs;
    const int local = i - block * bs;
    const int this_tile_start = block * bs;
    const int next_tile_start = (block + 1) * bs;
    const int start = i - (mask_width / 2);

    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      int in_index = start + j;
      if (in_index >= 0 && in_index < input_width) {
        if (in_index >= this_tile_start && in_index < next_tile_start) {
          s += in[this_tile_start + (local + j - (mask_width / 2))] * mask[j];
        } else {
          s += in[in_index] * mask[j];
        }
      }
    }
    out[i] = s;
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs((double)s - (double)d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = (size_t)input_width * sizeof(T);

  T *a = (T *)malloc(size_bytes);
  T *b = (T *)malloc(size_bytes);

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = (T)(rand() % 256);
  }

  int dev = omp_get_default_device();
  int host = omp_get_initial_device();

  T *d_a = (T *)omp_target_alloc(size_bytes, dev);
  T *d_b = (T *)omp_target_alloc(size_bytes, dev);
  T *d_mask = (T *)omp_target_alloc((size_t)mask_width * sizeof(T), dev);

  if (d_a == NULL || d_b == NULL || d_mask == NULL) {
    printf("OpenMP target allocation failed\n");
    exit(1);
  }

  OMP_CHECK(omp_target_memcpy(d_a, a, size_bytes, 0, 0, dev, host));
  OMP_CHECK(omp_target_memcpy(d_mask, h_mask, (size_t)mask_width * sizeof(T), 0, 0, dev, host));

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_kernel(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_kernel(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_caching_kernel(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  omp_target_free(d_a, dev);
  omp_target_free(d_b, dev);
  omp_target_free(d_mask, dev);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);

  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width);

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
